// Free releases the resources held by this handle.
func (h *VisitorHandle) Free() {
	if h.ptr != nil {
		C.htm_visitor_handle_free((*C.HTMVisitorHandle)(h.ptr))
		h.ptr = nil
	}
}

// Convert Convert HTML to Markdown, returning a [`ConversionResult`] with content, metadata, images,

// and warnings.
//
// # Arguments
//
// * `html` — the HTML string to convert.
// * `options` — optional conversion options. Defaults to [`ConversionOptions::default`].
//
// # Example
//
// ```
// use html_to_markdown_rs::convert;
//
// let html = "<h1>Hello World</h1>";
// let result = convert(html, None).unwrap();
// assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
// ```
//
// # Errors
//
// Returns an error if HTML parsing fails or if the input contains invalid UTF-8.
func Convert(html string, options *ConversionOptions) (*ConversionResult, error) {
	if options != nil && options.Visitor != nil {
		return convertWithVisitorHelper(html, options, options.Visitor)
	}

	cHTML := C.CString(html)
	defer C.free(unsafe.Pointer(cHTML))

	var cOptions *C.HTMConversionOptions
	if options != nil {
		jsonBytes, err := json.Marshal(options)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal options: %w", err)
		}
		tmpStr := C.CString(string(jsonBytes))
		cOptions = C.htm_conversion_options_from_json(tmpStr)
		C.free(unsafe.Pointer(tmpStr))
		defer C.htm_conversion_options_free(cOptions)
	}

	ptr := C.htm_convert(cHTML, cOptions)
	if ptr == nil {
		if err := lastError(); err != nil {
			return nil, err
		}
		return nil, fmt.Errorf("conversion returned nil")
	}
	defer C.htm_conversion_result_free(ptr)

	jsonPtr := C.htm_conversion_result_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert result to JSON")
	}
	defer C.htm_free_string(jsonPtr)
	var result ConversionResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal result: %w", err)
	}
	return &result, nil
}

// IsValid IsValid validate that the header level is within valid range (1-6).

// # Returns
//
// `true` if level is 1-6, `false` otherwise.
//
// # Examples
//
// ```
// let valid = HeaderMetadata {
// level: 3,
// text: "Title".to_string(),
// id: None,
// depth: 2,
// html_offset: 100,
// };
// assert!(valid.is_valid());
//
// let invalid = HeaderMetadata {
// level: 7,  // Invalid
// text: "Title".to_string(),
// id: None,
// depth: 2,
// html_offset: 100,
// };
// assert!(!invalid.is_valid());
// ```
func (r *HeaderMetadata) IsValid() (*bool, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.htm_header_metadata_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return nil, fmt.Errorf("failed to create receiver: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_header_metadata_free(cRecv)
	ptr := C.htm_header_metadata_is_valid(cRecv)
	return func() *bool { v := ptr != 0; return &v }(), nil
}

// ApplyUpdate ApplyUpdate apply a partial update to these conversion options.

func (r *ConversionOptions) ApplyUpdate(
	update ConversionOptionsUpdate) error {
	jsonBytescUpdate, err := json.Marshal(update)
	if err != nil {
		return fmt.Errorf("failed to marshal: %w", err)
	}
	// When the parameter is a nil pointer (Option<&T> on the Rust side), json.Marshal
	// emits "null" which the FFI's _from_json rejects. Substitute "{}" so a default
	// instance is constructed instead — semantically equivalent to None for query types
	// whose fields are all optional with serde(default).
	if string(jsonBytescUpdate) == "null" {
		jsonBytescUpdate = []byte("{}")
	}
	tmpStrcUpdate := C.CString(string(jsonBytescUpdate))
	cUpdate := C.htm_conversion_options_update_from_json(tmpStrcUpdate)
	C.free(unsafe.Pointer(tmpStrcUpdate))
	if cUpdate == nil {
		return fmt.Errorf("failed to create conversion_options_update: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_conversion_options_update_free(cUpdate)

	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.htm_conversion_options_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return fmt.Errorf("failed to create receiver: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_conversion_options_free(cRecv)
	C.htm_conversion_options_apply_update(cRecv, cUpdate)
	jsonPtrUpdated := C.htm_conversion_options_to_json(cRecv)
	if jsonPtrUpdated != nil {
		_ = json.Unmarshal([]byte(C.GoString(jsonPtrUpdated)), r)
		C.htm_free_string(jsonPtrUpdated)
	}
	return nil
}

